<script>
const DATA = __JSON_DATA__;
const TOKEN = new URLSearchParams(window.location.search).get('token') || '';
const ACTION_URL = window.location.origin + '/webhook/bejauha-dashboard-action';
let activeTab = 'todos';
let searchText = '';
let activeFilter = null;
let modalCtx = null;

document.getElementById('s-todos').textContent = (DATA.leads || []).length;
document.getElementById('s-clientes').textContent = (DATA.clientes_paquete || []).length;
document.getElementById('s-handoffs').textContent = (DATA.handoffs || []).length;

document.querySelectorAll('.tab').forEach(t => {
  t.addEventListener('click', () => {
    document.querySelectorAll('.tab').forEach(x => x.classList.remove('active'));
    t.classList.add('active');
    activeTab = t.dataset.tab;
    activeFilter = null;
    document.getElementById('search').value = '';
    searchText = '';
    render();
  });
});
document.getElementById('search').addEventListener('input', e => { searchText = e.target.value.toLowerCase().trim(); render(); });

function matchSearch(item) {
  if (!searchText) return true;
  const n = (item.nombre || '').toLowerCase();
  const t = (item.telefono || '').toLowerCase();
  return n.includes(searchText) || t.includes(searchText);
}
function bdg(text, type) {
  const cls = type ? 'bdg-' + type : 'bdg-soft';
  return '<span class="bdg ' + cls + '">' + text + '</span>';
}
function esc(s) { return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&#39;'); }

function actionsHtml(tel, nombre, saldoActual) {
  const saldoArg = (saldoActual === undefined || saldoActual === null) ? 'null' : saldoActual;
  const nombreEsc = esc(nombre).replace(/'/g,"\\u0027");
  return '<div class="actions-row">' +
    '<button class="action-btn asis" onclick="event.stopPropagation();confirmAsistencia(\'' + tel + '\',\'' + nombreEsc + '\',this)">+1 Asistencia</button>' +
    '<button class="action-btn saldo" onclick="event.stopPropagation();openSaldoModal(\'' + tel + '\',\'' + nombreEsc + '\',' + saldoArg + ')">Cargar/ajustar clases</button>' +
    '<button class="action-btn" style="background:#5a6b7d" onclick="event.stopPropagation();openEditNombreModal(\'' + tel + '\',\'' + nombreEsc + '\')">Editar nombre</button>' +
    '<button class="action-btn" style="background:#7a5a40" onclick="event.stopPropagation();openEditTelModal(\'' + tel + '\',\'' + nombreEsc + '\')">Editar teléfono</button>' +
    '</div>';
}

function renderTodos() {
  let items = (DATA.leads || []).filter(matchSearch);
  const filters = [
    { label: 'Asignados a humano', match: x => x.asignado_humano },
    { label: 'WhatsApp', match: x => x.canal === 'whatsapp' || x.canal === 'ambos' },
    { label: 'Instagram', match: x => x.canal === 'instagram' || x.canal === 'ambos' },
    { label: 'Opt-out', match: x => x.opt_out_marketing }
  ];
  if (activeFilter !== null && filters[activeFilter]) items = items.filter(filters[activeFilter].match);
  const filtersHtml = filters.map((f, i) =>
    '<button class="chip ' + (activeFilter === i ? 'active' : '') + '" data-fidx="' + i + '">' + f.label + '</button>'
  ).join('');
  return renderList(items, item => {
    const badges = [];
    if (item.asignado_humano) badges.push(bdg('Asignado humano', 'warn'));
    if (item.opt_out_marketing) badges.push(bdg('Opt-out', 'danger'));
    if (item.tipificacion) badges.push(bdg(item.tipificacion, 'info'));
    if (item.canal) badges.push(bdg(item.canal, 'soft'));
    return {
      nombre: item.nombre || '(sin nombre)',
      tel: item.telefono ? '+' + item.telefono : '(sin teléfono)',
      badges: badges,
      detail: [
        ['Origen', item.origen || '—'],
        ['Clasificación', item.clasificacion || '(sin clasificar)'],
        ['Canal', item.canal || '—'],
        ['Instagram', item.instagram || '—'],
        ['Email', item.email || '—'],
        ['Último contacto', item.ultimo_contacto || '—']
      ],
      actions: item.telefono ? actionsHtml(item.telefono, item.nombre || '(sin nombre)') : ''
    };
  }, filtersHtml);
}

function renderClientes() {
  let items = (DATA.clientes_paquete || []).filter(matchSearch);
  const filters = [
    { label: 'Con saldo', match: x => x.clases_restantes > 0 },
    { label: 'Saldo 0', match: x => x.clases_restantes === 0 },
    { label: 'En pausa', match: x => x.pausado },
    { label: 'En handoff', match: x => x.asignado_humano }
  ];
  if (activeFilter !== null && filters[activeFilter]) items = items.filter(filters[activeFilter].match);
  const filtersHtml = filters.map((f, i) =>
    '<button class="chip ' + (activeFilter === i ? 'active' : '') + '" data-fidx="' + i + '">' + f.label + '</button>'
  ).join('');
  return renderList(items, item => {
    const badges = [];
    badges.push(bdg(item.clases_restantes + ' clase' + (item.clases_restantes === 1 ? '' : 's'), item.clases_restantes <= 1 ? 'warn' : 'success'));
    badges.push(bdg('Vence ' + (item.vence_at || '?'), 'info'));
    if (item.pausado) badges.push(bdg('En pausa desde ' + (item.pausa_inicio || '?'), 'warn'));
    if (item.asignado_humano) badges.push(bdg('Handoff activo', 'danger'));
    const asisLines = (item.asistencias_recientes || []).map(a => {
      const marker = a.sin_saldo ? '💰 Deudor' : '✓';
      return '<div class="asis-line"><span>' + marker + ' · ' + a.fecha + '</span><span>' + (a.ts || '') + '</span></div>';
    }).join('');
    return {
      nombre: item.nombre || '(sin nombre)',
      tel: item.telefono ? '+' + item.telefono : '(sin teléfono)',
      badges: badges,
      detail: [
        ['Tipo de paquete', item.tipo || '—'],
        ['Pausa usada', (item.pausa_count || 0) + ' de 1'],
        ['Total asistencias históricas', item.asistencias_count || 0],
        ['Tipificación', item.tipificacion || '—'],
        ['Últimas 5 asistencias', '<div>' + (asisLines || '<em>Sin registros</em>') + '</div>']
      ],
      actions: actionsHtml(item.telefono, item.nombre || '(sin nombre)', item.clases_restantes)
    };
  }, filtersHtml);
}

function renderHandoffs() {
  let items = (DATA.handoffs || []).filter(matchSearch);
  return renderList(items, item => {
    const badges = [];
    badges.push(bdg(item.horas_pendiente + 'h pendiente', item.horas_pendiente >= 36 ? 'warn' : 'info'));
    badges.push(bdg(item.origen_agente || 'inbound', 'soft'));
    if (item.canal) badges.push(bdg(item.canal, 'soft'));
    return {
      nombre: item.nombre || '(sin nombre)',
      tel: item.telefono ? '+' + item.telefono : '(sin teléfono)',
      badges: badges,
      detail: [
        ['Creado', item.creado],
        ['Origen', item.origen_agente || '—'],
        ['Canal del cliente', item.canal || '—'],
        ['Resumen', item.resumen || '—']
      ],
      actions: ''
    };
  }, '');
}

function renderList(items, mapper, filtersHtml) {
  document.getElementById('filters').innerHTML = filtersHtml || '';
  document.querySelectorAll('.chip').forEach(c => {
    c.addEventListener('click', () => {
      const idx = parseInt(c.dataset.fidx, 10);
      activeFilter = (activeFilter === idx) ? null : idx;
      render();
    });
  });
  const list = document.getElementById('list');
  if (!items || items.length === 0) {
    list.innerHTML = '<div class="empty"><h3>Sin resultados</h3><p>No hay items para mostrar con esos filtros.</p></div>';
    return;
  }
  const html = items.map((it, i) => {
    const mapped = mapper(it);
    const badgesHtml = mapped.badges.join('');
    const detailHtml = mapped.detail.map(d =>
      '<div class="dr"><span class="dr-label">' + d[0] + '</span><span class="dr-value">' + d[1] + '</span></div>'
    ).join('');
    return '<div class="item" data-idx="' + i + '">' +
           '<div class="item-header"><div><div class="item-name">' + esc(mapped.nombre) + '</div>' +
           '<div class="item-tel">' + esc(mapped.tel) + '</div></div><span class="chev">▾</span></div>' +
           '<div class="item-meta">' + badgesHtml + '</div>' +
           '<div class="item-detail">' + detailHtml + (mapped.actions || '') + '</div>' +
           '</div>';
  }).join('');
  list.innerHTML = html;
  document.querySelectorAll('.item-header').forEach(h => {
    h.addEventListener('click', () => h.closest('.item').classList.toggle('open'));
  });
}

function render() {
  if (activeTab === 'todos') renderTodos();
  else if (activeTab === 'clientes') renderClientes();
  else if (activeTab === 'handoffs') renderHandoffs();
}

function showToast(msg, isError) {
  const t = document.getElementById('toast');
  t.textContent = msg;
  t.className = 'toast show' + (isError ? ' error' : '');
  setTimeout(() => t.className = 'toast', 3500);
}

async function postAction(action, params, btn) {
  if (!TOKEN) { showToast('Falta token en la URL', true); return null; }
  if (btn) { btn.disabled = true; btn.dataset.oldText = btn.textContent; btn.textContent = '...'; }
  try {
    const resp = await fetch(ACTION_URL, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(Object.assign({ token: TOKEN, action }, params))
    });
    const data = await resp.json();
    showToast(data.message || (data.ok ? 'Hecho' : 'Error'), !data.ok);
    if (data.ok) setTimeout(() => window.location.reload(), 1200);
    return data;
  } catch (e) {
    showToast('Error de red: ' + e.message, true);
    return null;
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = btn.dataset.oldText || ''; }
  }
}

function openCreateModal() {
  document.getElementById('m-telefono').value = '';
  document.getElementById('m-nombre').value = '';
  document.getElementById('modal-create').classList.add('open');
  setTimeout(() => document.getElementById('m-telefono').focus(), 50);
}
function openSaldoModal(telefono, nombre, saldoActual) {
  modalCtx = { telefono: telefono, nombre: nombre };
  const info = nombre + ' (' + telefono + ')' + (saldoActual !== null && saldoActual !== undefined ? ' · Saldo actual: ' + saldoActual : '');
  document.getElementById('m-saldo-info').textContent = info;
  document.getElementById('m-clases').value = (saldoActual !== null && saldoActual !== undefined) ? saldoActual : '';
  document.getElementById('modal-saldo').classList.add('open');
  setTimeout(() => document.getElementById('m-clases').focus(), 50);
}
function closeModal(id) { document.getElementById(id).classList.remove('open'); }

async function submitCreateLead() {
  const tel = document.getElementById('m-telefono').value.trim();
  const nombre = document.getElementById('m-nombre').value.trim();
  if (!tel || nombre.length < 2) { showToast('Faltan datos (tel + nombre)', true); return; }
  const btn = document.getElementById('btn-submit-create');
  const r = await postAction('create_lead', { telefono: tel, nombre: nombre }, btn);
  if (r && r.ok) closeModal('modal-create');
}
async function submitAjustarSaldo() {
  const clases = document.getElementById('m-clases').value;
  if (clases === '' || isNaN(parseInt(clases))) { showToast('Indica un número de clases', true); return; }
  if (!modalCtx) return;
  const btn = document.getElementById('btn-submit-saldo');
  const r = await postAction('ajustar_saldo', { telefono: modalCtx.telefono, clases: parseInt(clases) }, btn);
  if (r && r.ok) closeModal('modal-saldo');
}
function confirmAsistencia(telefono, nombre, btn) {
  if (!confirm('¿Registrar 1 asistencia para ' + nombre + '?')) return;
  postAction('asistencia', { telefono: telefono }, btn);
}

